import React, { useState } from 'react';
import HighchartsReact from 'highcharts-react-official';
import Highcharts from 'highcharts';
import { buildChartConfig } from '../utils/chartUtils';
import DataTable from './DataTable';
import './ChatMessage.css';

const TABS = [
  { id: 'bar',   icon: '▬', label: 'Bar'   },
  { id: 'line',  icon: '〰', label: 'Line'  },
  { id: 'pie',   icon: '◉', label: 'Pie'   },
  { id: 'table', icon: '⊞', label: 'Table' },
];

export default function ChatMessage({ message }) {
  const { role, text, queryResult } = message;
  const [activeChart, setActiveChart] = useState(message.chartType || 'bar');
  const [showCode, setShowCode]       = useState(false);
  const [copied, setCopied]           = useState(false);

  const isUser   = role === 'user';
  const isError  = role === 'error';
  const hasData  = queryResult && Array.isArray(queryResult.data) && queryResult.data.length > 0;
  const isScalar = queryResult && !Array.isArray(queryResult.data) && queryResult.data !== null;

  const chartConfig = hasData && activeChart !== 'table'
    ? buildChartConfig(activeChart, queryResult.data, queryResult.question || '')
    : null;

  const handleCopy = () => {
    navigator.clipboard.writeText(queryResult?.generated_code || '');
    setCopied(true);
    setTimeout(() => setCopied(false), 1800);
  };

  return (
    <div className={`msg-wrapper ${role}`}>
      <div className={`msg-avatar ${role}`}>
        {isUser ? '◈' : isError ? '⚠' : '✦'}
      </div>

      <div className="msg-body">
        <span className="msg-role">{isUser ? 'You' : isError ? 'Error' : 'FlightIQ'}</span>

        <div className={`msg-bubble ${role}`}>
          <p className="msg-text">{text}</p>
          {isScalar && (
            <div className="scalar-box">
              <span className="scalar-label">Result</span>
              <span className="scalar-value">{String(queryResult.data)}</span>
            </div>
          )}
        </div>

        {hasData && (
          <div className="data-panel">
            <div className="panel-header">
              <div className="panel-meta">
                <span className="meta-badge rows">{queryResult.row_count} rows</span>
                {queryResult.columns && (
                  <span className="meta-badge cols">{queryResult.columns.length} cols</span>
                )}
              </div>

              <div className="chart-switcher">
                {TABS.map(({ id, icon, label }) => (
                  <button
                    key={id}
                    className={`chart-tab ${activeChart === id ? 'active' : ''}`}
                    onClick={() => setActiveChart(id)}
                  >
                    <span>{icon}</span>
                    <span>{label}</span>
                  </button>
                ))}
              </div>

              {queryResult.generated_code && (
                <button
                  className={`code-toggle-btn ${showCode ? 'active' : ''}`}
                  onClick={() => setShowCode(v => !v)}
                >
                  {showCode ? 'Hide' : '</> Query'}
                </button>
              )}
            </div>

            {showCode && queryResult.generated_code && (
              <div className="code-block">
                <div className="code-header">
                  <span>Generated Pandas Query</span>
                  <button className="copy-btn" onClick={handleCopy}>
                    {copied ? '✓ Copied' : 'Copy'}
                  </button>
                </div>
                <pre>{queryResult.generated_code}</pre>
              </div>
            )}

            <div className="chart-area">
              {activeChart === 'table' || !chartConfig ? (
                <DataTable data={queryResult.data} columns={queryResult.columns} />
              ) : (
                <HighchartsReact
                  highcharts={Highcharts}
                  options={chartConfig}
                  containerProps={{ style: { width: '100%', height: '340px' } }}
                />
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
